"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[168],{3168:function(e,o){o.Z={id:"chapter-4-2",subject:"science",title:"4.2 Light & Matter",emoji:"\uD83D\uDD26",description:"Learn everything about how light interacts with different objects — and how to stay safe in the sun!",objectives:["\uD83D\uDC41️ How we see objects","\uD83E\uDEA8 Opaque & Shadows","\uD83E\uDE9F Transparent","\uD83C\uDF2B️ Translucent","☀️ Sun Safety","\uD83C\uDF08 Colors of Light"],concepts:[{id:"how-we-see",title:"How Light Lets Us See",subtitle:"Light reflects off objects into your eyes",emoji:"\uD83D\uDCA1",color:"blue",explanation:"Imagine you're reading a book with a lamp on. The lamp sends out light. That light hits the book and <strong>bounces back</strong> (reflects) into your eyes. That's how you see things that don't glow on their own!\n\nWhen light hits any object, <strong>3 things can happen</strong>: it can bounce back (reflect), be soaked up (absorbed), or bend through (refract). Often all three happen at once!",demoType:"seeDemo",lightInteractions:[{emoji:"\uD83E\uDE9E",label:"Reflected",color:"blue",description:"Light bounces back off the surface"},{emoji:"\uD83D\uDD25",label:"Absorbed",color:"coral",description:"Light is soaked into the object"},{emoji:"〰️",label:"Refracted",color:"purple",description:"Light bends as it passes through"}],examples:[]},{id:"opaque",title:"Opaque",subtitle:"Light CANNOT pass through → Shadow forms!",emoji:"\uD83E\uDEA8",color:"grey",explanation:"<strong>Opaque</strong> objects block ALL light. They only reflect or absorb it. Because no light gets through, a dark shape called a <strong>shadow</strong> forms on the other side!\n\nYour body is opaque. That's why you cast a shadow on a sunny day. Thick wood, aluminum foil, and cardboard are all opaque.",demoType:"opaque",examples:[{emoji:"\uD83E\uDE9F",label:"Wooden door"},{emoji:"\uD83E\uDDF1",label:"Brick wall"},{emoji:"\uD83C\uDF2B️",label:"Aluminum foil"},{emoji:"\uD83D\uDCDA",label:"Thick cardboard"},{emoji:"\uD83E\uDDCD",label:"Your body!"}]},{id:"transparent",title:"Transparent",subtitle:"Light passes through FULLY → you see clearly",emoji:"\uD83E\uDE9F",color:"teal",explanation:"<strong>Transparent</strong> objects let ALL the light pass straight through them. You can see what's on the other side perfectly clearly. No shadow is formed because light passes right through!",demoType:"transparent",examples:[{emoji:"\uD83E\uDE9F",label:"Glass window"},{emoji:"\uD83D\uDCA7",label:"Water"},{emoji:"\uD83E\uDDF4",label:"Clear plastic bottle"},{emoji:"\uD83C\uDF2C️",label:"Air"},{emoji:"\uD83D\uDD2D",label:"Eyeglasses lens"}]},{id:"translucent",title:"Translucent",subtitle:"SOME light passes through → things look blurry",emoji:"\uD83C\uDF2B️",color:"purple",explanation:"<strong>Translucent</strong> objects are in between opaque and transparent. They let <strong>some</strong> light through but block the rest. The light that gets through is scattered, making things on the other side look <strong>blurry</strong>.",demoType:"translucent",examples:[{emoji:"\uD83D\uDCC4",label:"Wax paper"},{emoji:"\uD83D\uDEBF",label:"Frosted glass"},{emoji:"\uD83C\uDFA8",label:"Colored tissue paper"},{emoji:"\uD83E\uDDEA",label:"Some plastics"}]},{id:"sun-safety",title:"Sun Safety",subtitle:"Protect your eyes and skin from the sun",emoji:"☀️",color:"yellow",explanation:"Sunlight can <strong>harm your eyes</strong> and cause <strong>sunburn on your skin</strong>. Always protect yourself on hot, sunny days! There are 3 great ways to stay safe:",demoType:"sunSafety",sunSafetyCards:[{emoji:"\uD83D\uDD76️",title:"Sunglasses",description:"Protect your eyes from harmful sunlight rays. Never look directly at the sun!"},{emoji:"\uD83E\uDDF4",title:"Sunscreen",description:"Apply on your skin before going outside. Prevents painful sunburns!"},{emoji:"\uD83E\uDDE2",title:"Hat & Shade",description:"A hat covers your head and face. Sitting in the shade also keeps you cool and safe!"}],examples:[]},{id:"colors-of-light",title:"Colors of Light",subtitle:"Sunlight is a mix of ALL colors!",emoji:"\uD83C\uDF08",color:"teal",explanation:"<strong>Sunlight looks white</strong>, but it's actually a mixture of ALL the colors of the rainbow! When light hits an object, the object <strong>absorbs</strong> some colors and <strong>reflects</strong> others. The color you see is the one that bounces back to your eyes!",demoType:"color",fruitCards:[{emoji:"\uD83C\uDF4B",name:"Yellow Lemon",description:"Reflects <strong>yellow</strong> light. Absorbs all other colors.",tagLabel:"Reflects Yellow",tagColor:"#F0D060",tagBg:"rgba(240,208,96,0.2)"},{emoji:"\uD83C\uDF4F",name:"Green Lime",description:"Reflects <strong>green</strong> light. Absorbs all other colors.",tagLabel:"Reflects Green",tagColor:"#3FB950",tagBg:"rgba(63,185,80,0.2)"},{emoji:"⬜",name:"White Object",description:"Reflects <strong>ALL</strong> colors of light back to your eyes.",tagLabel:"Reflects All",tagColor:"#475569",tagBg:"rgba(100,116,139,0.12)"},{emoji:"⬛",name:"Black Object",description:"Absorbs <strong>ALL</strong> colors. Reflects none back to you.",tagLabel:"Absorbs All",tagColor:"#334155",tagBg:"rgba(30,41,59,0.08)"}],examples:[]}],flashcards:[{emoji:"\uD83E\uDEA8",word:"OPAQUE",color:"#90A4AE",bgFront:"rgba(96,125,139,0.12)",borderFront:"rgba(96,125,139,0.3)",bgBack:"rgba(96,125,139,0.18)",borderBack:"rgba(96,125,139,0.4)",definition:"Light <strong>CANNOT</strong> pass through. Makes a <strong>shadow</strong>!",example:"\uD83E\uDEA8 Wood, foil, cardboard, your body"},{emoji:"\uD83E\uDE9F",word:"TRANSPARENT",color:"#0891B2",bgFront:"rgba(79,195,247,0.08)",borderFront:"rgba(79,195,247,0.3)",bgBack:"rgba(79,195,247,0.12)",borderBack:"rgba(79,195,247,0.4)",definition:"Light passes through <strong>FULLY</strong>. See clearly!",example:"\uD83E\uDE9F Glass, water, clear plastic"},{emoji:"\uD83C\uDF2B️",word:"TRANSLUCENT",color:"#7C3AED",bgFront:"rgba(188,140,255,0.08)",borderFront:"rgba(188,140,255,0.3)",bgBack:"rgba(188,140,255,0.12)",borderBack:"rgba(188,140,255,0.4)",definition:"<strong>SOME</strong> light passes. Things look <strong>blurry</strong>!",example:"\uD83C\uDF2B️ Wax paper, frosted glass"},{emoji:"\uD83C\uDF11",word:"SHADOW",color:"#D97706",bgFront:"rgba(240,208,96,0.08)",borderFront:"rgba(240,208,96,0.3)",bgBack:"rgba(240,208,96,0.12)",borderBack:"rgba(240,208,96,0.4)",definition:"Dark shape formed when an <strong>opaque</strong> object blocks light!",example:"\uD83C\uDF11 Your shadow on a sunny day"}],comparison:{columns:[{emoji:"\uD83E\uDEA8",title:"OPAQUE",color:"#90A4AE",bgColor:"rgba(96,125,139,0.1)",descriptions:["No light passes","Shadow forms","Can't see through"]},{emoji:"\uD83E\uDE9F",title:"TRANSPARENT",color:"#0891B2",bgColor:"rgba(79,195,247,0.06)",descriptions:["All light passes","No shadow","See clearly"]},{emoji:"\uD83C\uDF2B️",title:"TRANSLUCENT",color:"#7C3AED",bgColor:"rgba(188,140,255,0.06)",descriptions:["Some light passes","Faint shadow","See blurry"]}]},quiz:[{q:"What do we call objects that do NOT let any light pass through them?",emoji:"\uD83E\uDEA8",opts:["Transparent","Translucent","Opaque","Shadow"],ans:2,fb:"Opaque objects block ALL light — that's exactly why they create shadows behind them!"},{q:"When an opaque object blocks light, what dark shape forms on the other side?",emoji:"\uD83C\uDF11",opts:["A rainbow","A shadow","A reflection","A beam"],ans:1,fb:"A shadow forms when light can't pass through an opaque object! The area behind gets no light."},{q:"Glass windows, water, and clear plastic are examples of which type of object?",emoji:"\uD83E\uDE9F",opts:["Opaque","Translucent","Shadow","Transparent"],ans:3,fb:"Transparent objects let ALL light pass through — you can see clearly through them!"},{q:"You look at a book through wax paper. The book looks BLURRY. Wax paper is...",emoji:"\uD83D\uDCD6",opts:["Transparent","Opaque","Translucent","Reflective"],ans:2,fb:"Translucent = some light passes, some is blocked → things always look blurry through it!"},{q:"How do we see objects like a book that don't make their own light?",emoji:"\uD83D\uDC41️",opts:["Books glow in the dark","Light bounces off the book into our eyes","Our eyes send out light beams","We can only see them in daylight"],ans:1,fb:"Light reflects (bounces) off objects and travels to our eyes — that's how we see!"},{q:"Which of these is an OPAQUE object?",emoji:"\uD83E\uDD14",opts:["Clear glass","Water","Aluminum foil","Air"],ans:2,fb:"Aluminum foil is opaque — it blocks ALL light! That's why you can't see through it."},{q:"What are THREE ways to stay safe in the sun?",emoji:"☀️",opts:["Sunglasses, sunscreen, and a hat","Dark glasses, water, and jumping","Sunscreen, eating, and sleeping","A hat, swimming, and staying awake"],ans:0,fb:"Sunglasses protect eyes, sunscreen protects skin, and a hat gives shade from the sun!"},{q:"Frosted glass lets SOME light through but things look blurry. Frosted glass is...",emoji:"\uD83E\uDDCA",opts:["Opaque","Transparent","Translucent","Invisible"],ans:2,fb:"Frosted glass is translucent — it only lets part of the light through, making things blurry!"},{q:"Sunlight is actually a mixture of...",emoji:"\uD83C\uDF08",opts:["Just yellow and white light","All the different colors of light","Only red, blue, and green","Heat and electricity"],ans:1,fb:"Sunlight contains ALL colors mixed together — that's why a prism creates a rainbow!"},{q:"Why does a green lime LOOK green?",emoji:"\uD83C\uDF4F",opts:["It absorbs green light and reflects all others","It reflects green light and absorbs all other colors","It makes its own green light","All fruits are green"],ans:1,fb:"Objects look the color they REFLECT! The lime reflects green and absorbs every other color."}],worksheet:{wordBank:["opaque","shadow","transparent","translucent","reflected"],fillBlanks:[{num:1,before:"A wooden door is",after:"because light cannot pass through it."},{num:2,before:"A glass window is",after:"because light passes through it fully."},{num:3,before:"Wax paper is",after:"because only some light passes through it."},{num:4,before:"When an opaque object blocks light, a dark",after:"is formed."},{num:5,before:"We can see objects because light is",after:"off them into our eyes."}],classify:{objects:["glass window","aluminum foil","wax paper","wooden door","clear water bottle","frosted glass"],categories:[{title:"OPAQUE",borderColor:"#90A4AE",titleColor:"#546E7A",count:2},{title:"TRANSPARENT",borderColor:"#4FC3F7",titleColor:"#0277BD",count:2},{title:"TRANSLUCENT",borderColor:"#CE93D8",titleColor:"#6A1B9A",count:2}]},trueOrFalse:[{num:1,statement:"Aluminum foil is transparent. You can see through it."},{num:2,statement:"A shadow forms when light passes completely through an object."},{num:3,statement:"Sunglasses, sunscreen, and hats help protect us from the sun."},{num:4,statement:"Sunlight is a mixture of all the different colors of light."},{num:5,statement:"Frosted glass is translucent — things look blurry through it."}],shortAnswer:[{num:1,question:"How do we see objects that don't make their own light?",points:1,lines:2},{num:2,question:"Name 3 ways to stay safe in sunlight.",points:3,lines:3}],answerKey:{fillBlanks:["opaque","transparent","translucent","shadow","reflected"],classify:{OPAQUE:["aluminum foil","wooden door"],TRANSPARENT:["glass window","clear water bottle"],TRANSLUCENT:["wax paper","frosted glass"]},trueOrFalse:[!1,!1,!0,!0,!0],shortAnswer:["Light bounces (reflects) off objects into our eyes","Sunglasses, sunscreen, hat/shade"]}}}}}]);